            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/lots"]""",
            Tags = """["lots","traceability","quality","reference"]""",
            ContentJson = """{"title":"Production Lots Field Reference","groups":[{"heading":"Lot Record Fields","items":[{"label":"Lot Number","value":"String, max 100 characters. Auto-generated if not provided (format: LOT-YYYYMMDD-NNN, e.g., LOT-20260415-001). Can be manually assigned for custom numbering schemes."},{"label":"Part ID (required)","value":"Integer, must be greater than 0. References the part this lot is associated with. Every lot must be tied to exactly one part."},{"label":"Quantity (required)","value":"Decimal, must be greater than 0. Fractional quantities are supported (the create form steps in 0.0001 increments) so material tracked by weight, volume, or length can be recorded — e.g., 12.5 kg or 3.75 m. The detail panel displays the quantity with up to 4 decimal places."},{"label":"Job ID (optional)","value":"Integer. References the production job that created this lot. Null for lots created from vendor receipts without a job."},{"label":"Production Run ID (optional)","value":"Integer. References the specific production run within a job. Provides finer granularity than job-level tracking."},{"label":"Purchase Order Line ID (optional)","value":"Integer. References the PO line that sourced this lot. Used when lot is created from receiving vendor material."},{"label":"Supplier Lot Number (optional)","value":"String, max 100 characters. The vendor's own batch/lot identifier. Critical for supplier accountability and recall investigations."},{"label":"Expiration Date (optional)","value":"DateTimeOffset (UTC). For materials with shelf life. Format: ISO 8601. Null for non-perishable materials."},{"label":"Notes (optional)","value":"String, max 2000 characters. Free-form notes: storage conditions, deviations, special handling instructions."},{"label":"Created At","value":"DateTimeOffset (UTC). Auto-set when the lot record is created. Used for chronological sorting."},{"label":"Created By","value":"String (User ID). Auto-set from the authenticated user. Audit trail for who created the lot."}]},{"heading":"API Endpoints","items":[{"label":"GET /api/v1/lots","value":"List lot records. Query parameters: partId (int, optional), jobId (int, optional), search (string, optional). Search matches against lot number, supplier lot number, and part number. Returns list sorted by CreatedAt descending."},{"label":"POST /api/v1/lots","value":"Create a new lot record. Request body: { partId (required), quantity (required), lotNumber (optional), jobId (optional), productionRunId (optional), purchaseOrderLineId (optional), supplierLotNumber (optional), expirationDate (optional), notes (optional) }. Returns 201 with Location header. Auto-generates lot number if not provided."},{"label":"GET /api/v1/lots/{lotNumber}/trace","value":"Traceability query. Returns the complete chain for a lot number: part info, linked jobs, production runs, purchase orders (with vendor name), bin locations (with quantities), and QC inspections (with inspector, status, date). Returns 404 if lot number not found."}]},{"heading":"Traceability View (Lot Detail Panel)","items":[{"label":"Header — Part Number","value":"The part this lot is associated with, shown at the top of the trace panel."},{"label":"Header — Quantity","value":"The lot quantity, rendered with up to 4 decimal places to support fractional UoM."},{"label":"Header — Supplier Lot #","value":"The vendor's batch identifier. Only shown when present."},{"label":"Header — Expires","value":"The expiration date (MM/dd/yyyy). Only shown when present."},{"label":"Trace History (events[])","value":"A single chronological timeline, NOT separate arrays. Each event has a type, reference number, description, and date. Event types are Job, ProductionRun, PurchaseOrder, BinLocation, and QcInspection, each shown with its own icon (work, precision_manufacturing, description, inventory_2, fact_check). Jobs, production runs, POs, bin locations, and inspections are merged into this one event stream rather than listed in five distinct sections."}]},{"heading":"Validation Rules","items":[{"label":"Part ID","value":"Required. Must be greater than 0. Must reference an existing part."},{"label":"Quantity","value":"Required. Decimal, must be greater than 0. Fractional values allowed (not restricted to whole units)."},{"label":"Lot Number","value":"Optional. Max 100 characters. If omitted, auto-generated as LOT-YYYYMMDD-NNN."},{"label":"Supplier Lot Number","value":"Optional. Max 100 characters."},{"label":"Notes","value":"Optional. Max 2000 characters."},{"label":"Expiration Date","value":"Optional. Must be a valid ISO 8601 date if provided."}]},{"heading":"Authorization","items":[{"label":"Required Roles","value":"Admin, Manager, Engineer, or Production Worker. All three endpoints share the same role requirement."},{"label":"Soft Deletes","value":"Lot records use soft delete (DeletedAt timestamp). Deleted lots are excluded from queries by the global query filter."}]},{"heading":"Auto-Generated Lot Number Format","items":[{"label":"Pattern","value":"LOT-YYYYMMDD-NNN"},{"label":"Prefix","value":"LOT- (fixed)"},{"label":"Date segment","value":"YYYYMMDD — the UTC date when the lot is created (e.g., 20260415)"},{"label":"Sequence","value":"NNN — zero-padded 3-digit counter, incremented per day (001, 002, ... 999)"},{"label":"Example","value":"LOT-20260415-003 = third lot created on April 15, 2026"},{"label":"Custom override","value":"Provide your own lotNumber in the POST body to skip auto-generation. Useful for customer-mandated or industry-specific numbering."}]},{"heading":"Related Entities","items":[{"label":"Part","value":"Required FK. The part this lot tracks. Navigation: Part.PartNumber, Part.Description."},{"label":"Job","value":"Optional FK. The production job that created or consumed this lot. Navigation: Job.JobNumber, Job.Title."},{"label":"ProductionRun","value":"Optional FK. The specific production run. Navigation: ProductionRun.RunNumber, ProductionRun.Status."},{"label":"PurchaseOrderLine","value":"Optional FK. The PO line for received material. Navigation: PurchaseOrderLine.PurchaseOrder.PONumber, PurchaseOrder.Vendor.CompanyName."},{"label":"BinContent","value":"Inventory bin contents can reference lot numbers. Matched by EntityType='part', EntityId=PartId, LotNumber."},{"label":"QcInspection","value":"Quality inspections reference lot numbers via the LotNumber field. Matched directly by lot number string."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Production Lots Knowledge Check",
